issues.body:
`HardwareKeyboard.instance.logicalKeysPressed` returns keys that was previously pressed instead of only the currently pressed key. Happens when pressing the meta key in addition to other keys, on Mac OS.

## Steps to Reproduce

1. flutter create --platforms web foo
2. Put attached code sample in lib/main.dart
3. flutter run -d chrome -t lib/main.dart
2. Open page in chrome
3. Press keys `cmd + k` and release
4. Press key `arrow left` and release
5. Check console output
6. See that the last keypress includes the key `k` when only the `arrow left` key was pressed

**Expected results:**
```
LogicalKeySet#4b191(keys: Meta Left)
LogicalKeySet#5c7f7(keys: Meta Left + Key K)
LogicalKeySet#6c398(keys: Arrow Left)
```

**Actual results:**
```
LogicalKeySet#4b191(keys: Meta Left)
LogicalKeySet#5c7f7(keys: Meta Left + Key K)
LogicalKeySet#6c398(keys: Arrow Left + Key K)
```

<details>
<summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: GlobalKeyboardListener(
        onKeyEvent: (KeyEvent event) {
          if (event is KeyDownEvent) {
            if (HardwareKeyboard.instance.logicalKeysPressed.isNotEmpty) {
              final pressedKeys = LogicalKeySet.fromSet(
                HardwareKeyboard.instance.logicalKeysPressed,
              );

              // ignore: avoid_print
              print(pressedKeys);
            }
          }
          return false;
        },
        child: const Text("hello"),
      ),
    );
  }
}

class GlobalKeyboardListener extends StatefulWidget {
  final bool Function(KeyEvent keyEvent) onKeyEvent;
  final Widget child;

  const GlobalKeyboardListener({
    required this.onKeyEvent,
    required this.child,
    Key? key,
  }) : super(key: key);

  @override
  State<GlobalKeyboardListener> createState() {
    return _GlobalKeyboardListenerState();
  }
}

class _GlobalKeyboardListenerState<T> extends State<GlobalKeyboardListener> {
  @override
  void initState() {
    startListen();
    super.initState();
  }

  @override
  void dispose() {
    stopListen();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return widget.child;
  }

  void startListen() {
    HardwareKeyboard.instance.addHandler(widget.onKeyEvent);
  }

  void stopListen() {
    HardwareKeyboard.instance.removeHandler(widget.onKeyEvent);
  }
}
```

</details>

