### Steps to reproduce

1. Run the sample app on macOS
2. Set the keyboard to Japanese - Kana
3. Type "krwkwr"
4. Press down arrow a three times to navigate between the suggestions (the suggestions panel will appear at the bottom of the screen)

### Expected results

The message "old text from delta doesn't match resulting text from previous delta" shouldn't be printed.

### Actual results

The message "old text from delta doesn't match resulting text from previous delta" is printed, because a delta is reported with an `oldText` that's different from the resulting text of the previously applied delta.

### Code sample

<details open><summary>Code sample</summary>

```dart
// ignore_for_file: avoid_print

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

void main() {
  runApp(
    const MaterialApp(
      home: Scaffold(
        body: TextInputExample(),
      ),
    ),
  );
}

class TextInputExample extends StatefulWidget {
  const TextInputExample({super.key});

  @override
  State<TextInputExample> createState() => _TextInputExampleState();
}

class _TextInputExampleState extends State<TextInputExample> implements DeltaTextInputClient {
  final FocusNode _focusNode = FocusNode();
  final GlobalKey _textKey = GlobalKey();

  TextInputConnection? _inputConnection;
  TextEditingValue _currentEditingValue = const TextEditingValue(
    text: '',
    selection: TextSelection.collapsed(offset: 0),
  );

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((timeStamp) {
      _attach();
    });
  }

  @override
  void dispose() {
    _focusNode.dispose();
    super.dispose();
  }

  @override
  void updateEditingValueWithDeltas(List<TextEditingDelta> textEditingDeltas) {
    TextEditingValue newEditingValue = _currentEditingValue;

    print('received ${textEditingDeltas.length} delta(s)');
    for (final delta in textEditingDeltas) {
      print('apply delta: $delta');
      if (delta.oldText != newEditingValue.text) {
        print('old text from delta doesn\'t match resulting text from previous delta');
        print('old text from current delta: ${delta.oldText}');
        print('the previous text was: ${newEditingValue.text}');
      }
      newEditingValue = delta.apply(newEditingValue);

      print('new editing value: $newEditingValue');
    }

    setState(() {
      _currentEditingValue = newEditingValue;
    });
  }

  void _attach() {
    if (_inputConnection != null) {
      return;
    }
    _inputConnection = TextInput.attach(
      this,
      const TextInputConfiguration(
        enableDeltaModel: true,
        inputType: TextInputType.multiline,
        textCapitalization: TextCapitalization.sentences,
        inputAction: TextInputAction.newline,
        keyboardAppearance: Brightness.light,
      ),
    );
    _inputConnection!.show();
    _inputConnection!.setEditingState(_currentEditingValue);
